<template>
  <div class="service-card" :class="`service-card--${layout}`" :style="blockStyle">
    <!-- Image -->
    <div v-if="widgetDisplay.showImage !== false" class="service-card__image">
      <img v-if="service.image" :src="service.image" />
    </div>

    <div class="service-card__content">
      <div class="service-card__title" v-html="service.name" />

      <div
        v-if="widgetDisplay.showDescription !== false"
        class="service-card__desc"
        v-html="service.description"
      />

      <div
        v-if="
          widgetDisplay.showQuantity !== false || widgetDisplay.showUnitPrice !== false
        "
        class="service-card__pricing"
        :style="pricingRowStyle"
      >
        <span v-if="widgetDisplay.showQuantity !== false">
          {{ service.quantity }} {{ service.unit }}
        </span>

        <span v-if="widgetDisplay.showUnitPrice !== false">
          {{ service.unitPrice }}
        </span>
      </div>

      <div v-if="widgetDisplay.showServicePrice !== false" class="service-card__footer">
        <div class="service-card__total" :style="pricingRowStyle">
          {{ total }}
        </div>

        <!-- BUTTON ONLY IF NOT VIEW -->
        <button
          v-if="canShowButton"
          class="service-card__button"
          :class="{ 'service-card__button--selected': selected }"
          @click="toggleSelect"
        >
          {{
            selected
              ? service.selectedButtonText || "Selected"
              : service.buttonText || "Select"
          }}
        </button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";

const emit = defineEmits(["toggle-select"]);

const props = defineProps<{
  service: any;
  layout: string;
  widgetDisplay: any;
  pricingStyle: any;
  itemStyle: any;
  selected: boolean;
  selectionMode: "view" | "single" | "multiple";
  selectionRequired: boolean;
}>();

/* -----------------------------
STATE GUARDS
----------------------------- */

const canSelect = computed(() => props.selectionMode !== "view");

const canShowButton = computed(() => {
  return canSelect.value && props.widgetDisplay?.showServicePrice !== false;
});

/* -----------------------------
TOTAL
----------------------------- */

const total = computed(() => {
  const symbol = String(props.service.unitPrice || "£").match(/[^0-9.,]/)?.[0] ?? "£";

  const qty = parseFloat(props.service.quantity) || 0;

  const price =
    parseFloat(String(props.service.unitPrice || "").replace(/[^0-9.]/g, "")) || 0;

  return `${symbol}${(qty * price).toLocaleString()}`;
});

/* -----------------------------
STYLE
----------------------------- */

const blockStyle = computed(() => {
  const s = props.itemStyle ?? {};

  return {
    background: s.bgColor ?? "#fff",
    borderRadius: `${s.borderRadius ?? 12}px`,
    boxShadow: s.shadow
      ? `0 ${s.shadow / 2}px ${s.shadow}px rgba(0,0,0,0.12)`
      : undefined,
  };
});

const pricingRowStyle = computed(() => ({
  fontFamily: props.pricingStyle?.fontFamily,
  fontSize: props.pricingStyle?.fontSize ? `${props.pricingStyle.fontSize}px` : undefined,
  color: props.pricingStyle?.color,
  fontWeight: props.pricingStyle?.bold ? "700" : undefined,
}));

/* -----------------------------
ACTION
----------------------------- */

function toggleSelect() {
  if (!canSelect.value) return;
  emit("toggle-select", props.service._id);
}
</script>

