<template>
  <div ref="triggerRef" class="fu-popover-wrap" @click="toggle">
    <slot name="trigger" />
  </div>
  <Teleport to="body">
    <Transition name="fu-popover">
      <div
        v-if="open"
        ref="popoverRef"
        class="fu-popover"
        :style="popoverStyle"
        tabindex="-1"
        @click.stop
      >
        <!-- Header -->
        <div
          v-if="$slots.header"
          class="fu-popover__header"
          :class="{ 'is-sticky': stickyHeader }"
        >
          <slot name="header" />
        </div>
        <!-- Body (ALWAYS scrollable) -->
        <div class="fu-popover__body customScrollBar">
          <slot />
        </div>
        <!-- Footer -->
        <div
          v-if="$slots.footer"
          class="fu-popover__footer"
          :class="{ 'is-sticky': stickyFooter }"
        >
          <slot name="footer" />
        </div>
      </div>
    </Transition>
  </Teleport>
</template>

<script setup lang="ts">
import { ref, nextTick, onMounted, onBeforeUnmount } from "vue";

export type FuPopoverAlign = "left" | "right" | "center";
export type FuPopoverSide = "bottom" | "top";

const props = defineProps<{
  align?: FuPopoverAlign;
  side?: FuPopoverSide;
  offset?: number;
  width?: string;
  maxHeight?: string;
  stickyHeader?: boolean;
  stickyFooter?: boolean;
}>();

const emit = defineEmits<{
  (e: "open"): void;
  (e: "close"): void;
}>();

const open = ref(false);
const triggerRef = ref<HTMLElement | null>(null);
const popoverRef = ref<HTMLElement | null>(null);

const popoverStyle = ref<Record<string, string | number>>({
  position: "fixed",
  visibility: "hidden",
  top: "-9999px",
  left: "-9999px",
  zIndex: 9999,
});

const stickyHeader = props.stickyHeader ?? false;
const stickyFooter = props.stickyFooter ?? false;

function toggle() {
  open.value ? close() : openPopover();
}

function openPopover() {
  popoverStyle.value = {
    position: "fixed",
    visibility: "hidden",
    top: "-9999px",
    left: "-9999px",
    width: props.width ?? "auto",
    zIndex: 9999,
    maxHeight: props.maxHeight ?? "none",
  };
  open.value = true;
  emit("open");
  nextTick(() =>
    requestAnimationFrame(() =>
      requestAnimationFrame(() => {
        position();
        nextTick(() => {
          const input = popoverRef.value?.querySelector<HTMLElement>("input, textarea");
          if (input) input.focus();
          // else popoverRef.value?.focus();
        });
      })
    )
  );
}

function close() {
  open.value = false;
  emit("close");
}

function position() {
  if (!triggerRef.value || !popoverRef.value) return;

  const t = triggerRef.value.getBoundingClientRect();
  const p = popoverRef.value.getBoundingClientRect();
  const pad = 8;
  const offset = props.offset ?? 6;

  const spaceBelow = window.innerHeight - t.bottom - pad;
  const spaceAbove = t.top - pad;

  let side = props.side ?? "bottom";

  if (side === "bottom" && p.height > spaceBelow && spaceAbove > spaceBelow) {
    side = "top";
  } else if (side === "top" && p.height > spaceAbove && spaceBelow > spaceAbove) {
    side = "bottom";
  }

  let top = side === "top" ? t.top - p.height - offset : t.bottom + offset;

  let left =
    props.align === "right"
      ? t.right - p.width
      : props.align === "center"
      ? t.left + t.width / 2 - p.width / 2
      : t.left;

  left = Math.max(pad, Math.min(left, window.innerWidth - p.width - pad));
  top = Math.max(pad, Math.min(top, window.innerHeight - p.height - pad));

  popoverStyle.value = {
    position: "fixed",
    top: `${top}px`,
    left: `${left}px`,
    width: props.width ?? "auto",
    maxHeight: props.maxHeight ?? "none",
    zIndex: 9999,
    visibility: "visible",
  };
}

function onClickOutside(e: MouseEvent) {
  if (!open.value) return;
  const t = e.target as Node;
  if (triggerRef.value?.contains(t)) return;
  if (popoverRef.value?.contains(t)) return;
  close();
}

onMounted(() => {
  window.addEventListener("mousedown", onClickOutside);
  window.addEventListener("resize", position);
  window.addEventListener("scroll", position, true);
});

onBeforeUnmount(() => {
  window.removeEventListener("mousedown", onClickOutside);
  window.removeEventListener("resize", position);
  window.removeEventListener("scroll", position, true);
});

defineExpose({ open: openPopover, close });
</script>

<style scoped>
.fu-popover-wrap {
  display: inline-flex;
  align-items: center;
}

.fu-popover {
  display: flex;
  flex-direction: column;
  background: var(--fu-surface-background);
  border: 0.5px solid var(--fu-border);
  border-radius: var(--fu-radius, 6px);
  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
  overflow: hidden;
}

/* HEADER */
.fu-popover__header {
  flex-shrink: 0;
}

.fu-popover__header.is-sticky {
  position: sticky;
  top: 0;
  z-index: 2;
  background: var(--fu-surface-background);
  border-bottom: 0.5px solid var(--fu-border);
}

/* BODY (SCROLL AREA) */
.fu-popover__body {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
}

/* FOOTER */
.fu-popover__footer {
  flex-shrink: 0;
}

.fu-popover__footer.is-sticky {
  position: sticky;
  bottom: 0;
  z-index: 2;
  background: var(--fu-surface-background);
  border-top: 0.5px solid var(--fu-border);
}

/* ANIMATION */
.fu-popover-enter-active,
.fu-popover-leave-active {
  transition: opacity 0.12s ease, transform 0.12s ease;
}

.fu-popover-enter-from,
.fu-popover-leave-to {
  opacity: 0;
  transform: translateY(4px) scale(0.98);
}
</style>
