<template>
  <div
    ref="triggerRef"
    class="fu-color-trigger"
    :class="`fu-color-trigger--${size}`"
    :style="{ backgroundColor: hexString }"
    role="button"
    tabindex="0"
    @click="togglePopover"
    @keydown.enter.prevent="togglePopover"
    @keydown.space.prevent="togglePopover"
  >
    <slot name="trigger" />
  </div>

  <Teleport to="body">
    <div v-if="open" class="fu-color-popover" :style="popoverStyle">
      <div
        class="fu-saturation"
        :style="paletteStyle"
        @pointerdown="onPalettePointer"
        @pointermove="(e) => e.buttons === 1 && onPalettePointer(e)"
      >
        <div class="fu-cursor" :style="{ left: sat + '%', top: 100 - val + '%' }" />
      </div>

      <div class="fu-controls">
        <div class="fu-preview" :style="{ backgroundColor: hexString }" />
        <div class="fu-sliders">
          <input type="range" min="0" max="360" v-model="hue" class="fu-hue" />
        </div>
      </div>

      <input
        class="fu-output"
        :value="outputInput"
        @input="onOutputInput"
        @blur="onOutputBlur"
        @keydown="onOutputKeydown"
        placeholder="#RRGGBB or rgb(...)"
      />
    </div>
  </Teleport>
</template>

<script setup lang="ts">
import { ref, computed, watch, nextTick, onMounted, onBeforeUnmount } from "vue";

type PopoverStyle = { top: string; left: string; transformOrigin?: string };
type ColorFormat = "hex" | "rgb";

const props = defineProps<{
  modelValue?: string;
  size?: "xs" | "sm" | "md";
}>();

const emit = defineEmits<{
  (e: "update:modelValue", value: string): void;
}>();

const size = computed(() => props.size ?? "md");

const open = ref(false);
const triggerRef = ref<HTMLElement | null>(null);
const popoverStyle = ref<PopoverStyle>({ top: "0px", left: "0px" });

function togglePopover() {
  open.value = !open.value;
  if (open.value) nextTick(positionPopover);
}

function positionPopover() {
  if (!triggerRef.value) return;
  const trigger = triggerRef.value.getBoundingClientRect();
  const popoverWidth = 260;
  const popoverHeight = 320;
  const padding = 8;

  let top = trigger.bottom + 6;
  let left = trigger.left;
  let origin = "top left";

  if (left + popoverWidth > window.innerWidth - padding) {
    left = trigger.right - popoverWidth;
    origin = "top right";
  }
  left = Math.max(padding, left);

  if (top + popoverHeight > window.innerHeight - padding) {
    top = trigger.top - popoverHeight - 6;
    origin = origin.includes("right") ? "bottom right" : "bottom left";
  }
  top = Math.max(padding, top);

  popoverStyle.value = {
    top: `${top + window.scrollY}px`,
    left: `${left + window.scrollX}px`,
    transformOrigin: origin,
  };
}

function onDocumentClick(e: MouseEvent) {
  if (!open.value) return;
  const t = e.target as Node;
  if (triggerRef.value?.contains(t) || (t as HTMLElement).closest(".fu-color-popover"))
    return;
  open.value = false;
}

onMounted(() => {
  window.addEventListener("mousedown", onDocumentClick);
  window.addEventListener("resize", positionPopover);
  if (props.modelValue) {
    outputInput.value = props.modelValue;
    applyInput(props.modelValue);
  }
});
onBeforeUnmount(() => {
  window.removeEventListener("mousedown", onDocumentClick);
  window.removeEventListener("resize", positionPopover);
});

const format = ref<ColorFormat>("hex");
const hue = ref(0);
const sat = ref(100);
const val = ref(100);
const outputInput = ref("");
const isTyping = ref(false);

function hsvToRgb(h: number, s: number, v: number) {
  s /= 100;
  v /= 100;
  const c = v * s;
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
  const m = v - c;
  let r = 0,
    g = 0,
    b = 0;
  if (h < 60) [r, g, b] = [c, x, 0];
  else if (h < 120) [r, g, b] = [x, c, 0];
  else if (h < 180) [r, g, b] = [0, c, x];
  else if (h < 240) [r, g, b] = [0, x, c];
  else if (h < 300) [r, g, b] = [x, 0, c];
  else [r, g, b] = [c, 0, x];
  return {
    r: Math.round((r + m) * 255),
    g: Math.round((g + m) * 255),
    b: Math.round((b + m) * 255),
  };
}

function rgbToHsv(r: number, g: number, b: number) {
  r /= 255;
  g /= 255;
  b /= 255;
  const max = Math.max(r, g, b),
    min = Math.min(r, g, b),
    d = max - min;
  let h = 0;
  if (d) {
    if (max === r) h = ((g - b) / d) % 6;
    else if (max === g) h = (b - r) / d + 2;
    else h = (r - g) / d + 4;
    h *= 60;
    if (h < 0) h += 360;
  }
  return {
    h: Math.round(h),
    s: Math.round((max === 0 ? 0 : d / max) * 100),
    v: Math.round(max * 100),
  };
}

function rgbToHex(r: number, g: number, b: number) {
  return (
    "#" +
    [r, g, b]
      .map((v) => v.toString(16).padStart(2, "0"))
      .join("")
      .toUpperCase()
  );
}
function rgbToString(r: number, g: number, b: number) {
  return `rgb(${r}, ${g}, ${b})`;
}

const rgb = computed(() => hsvToRgb(hue.value, sat.value, val.value));
const hexString = computed(() => rgbToHex(rgb.value.r, rgb.value.g, rgb.value.b));
const paletteStyle = computed(() => ({
  background: `linear-gradient(to top, black, transparent), linear-gradient(to right, white, hsl(${hue.value}, 100%, 50%))`,
}));

function emitColor() {
  const { r, g, b } = rgb.value;
  emit(
    "update:modelValue",
    format.value === "rgb" ? rgbToString(r, g, b) : hexString.value
  );
}

function applyInput(value: string) {
  const v = value.trim().replace(/;$/, "");
  let parsed: { r: number; g: number; b: number } | null = null;
  if (/^#([0-9a-f]{6})$/i.test(v)) {
    format.value = "hex";
    parsed = {
      r: parseInt(v.slice(1, 3), 16),
      g: parseInt(v.slice(3, 5), 16),
      b: parseInt(v.slice(5, 7), 16),
    };
  }
  const m = v.match(/^rgba?\((\d{1,3}),\s*(\d{1,3}),\s*(\d{1,3})/);
  if (m) {
    format.value = "rgb";
    parsed = { r: +m[1], g: +m[2], b: +m[3] };
  }
  if (!parsed) return;
  const hsv = rgbToHsv(parsed.r, parsed.g, parsed.b);
  hue.value = hsv.h;
  sat.value = hsv.s;
  val.value = hsv.v;
  emitColor();
}

function onOutputInput(e: Event) {
  isTyping.value = true;
  outputInput.value = (e.target as HTMLInputElement).value;
}
function onOutputBlur() {
  isTyping.value = false;
  applyInput(outputInput.value);
}
function onOutputKeydown(e: KeyboardEvent) {
  if (e.key === "Enter") onOutputBlur();
}

function onPalettePointer(e: PointerEvent) {
  format.value = "hex";
  const el = e.currentTarget as HTMLElement;
  const r = el.getBoundingClientRect();
  sat.value = Math.round(
    (Math.min(Math.max(0, e.clientX - r.left), r.width) / r.width) * 100
  );
  val.value = Math.round(
    100 - (Math.min(Math.max(0, e.clientY - r.top), r.height) / r.height) * 100
  );
  emitColor();
}

watch(
  () => props.modelValue,
  (v) => {
    if (!v) return;
    outputInput.value = v;
    applyInput(v);
  }
);
</script>

