<template>
  <div class="fu-signature-wrapper">
    <canvas
      ref="canvas"
      @mousedown="startDrawing"
      @mousemove="draw"
      @mouseup="stopDrawing"
      @touchstart.prevent="startDrawing"
      @touchmove.prevent="draw"
      @touchend.prevent="stopDrawing"
    ></canvas>

    <div class="fu-signature-controls">
      <button type="button" @click="clear" class="fu-clear-btn">Clear Canvas</button>
    </div>
  </div>
</template>

<script setup>
import { ref, onMounted, onBeforeUnmount, watch } from "vue";

const props = defineProps({
  image: { type: String, default: null }, // v-model:image
  color: { type: String, default: "#111827" },
  lineWidth: { type: Number, default: 2.5 },
});

const emit = defineEmits(["update:image"]);

const canvas = ref(null);
const ctx = ref(null);
const isDrawing = ref(false);

// Initialize Canvas
onMounted(() => {
  const c = canvas.value;
  ctx.value = c.getContext("2d");
  resizeCanvas();
  window.addEventListener("resize", resizeCanvas);

  // If there's an existing image passed in, draw it (useful for switching tabs back)
  if (props.image) {
    const img = new Image();
    img.onload = () => ctx.value.drawImage(img, 0, 0);
    img.src = props.image;
  }
});

onBeforeUnmount(() => {
  window.removeEventListener("resize", resizeCanvas);
});

const resizeCanvas = () => {
  const c = canvas.value;
  const rect = c.getBoundingClientRect();
  const dpr = window.devicePixelRatio || 1;

  c.width = rect.width * dpr;
  c.height = rect.height * dpr;

  ctx.value.setTransform(1, 0, 0, 1, 0, 0); // RESET FIRST
  ctx.value.scale(dpr, dpr);

  ctx.value.strokeStyle = props.color;
  ctx.value.lineWidth = props.lineWidth;
  ctx.value.lineCap = "round";
  ctx.value.lineJoin = "round";
};

const getPos = (e) => {
  const rect = canvas.value.getBoundingClientRect();
  const clientX = e.clientX || (e.touches && e.touches[0].clientX);
  const clientY = e.clientY || (e.touches && e.touches[0].clientY);
  return {
    x: clientX - rect.left,
    y: clientY - rect.top,
  };
};

const startDrawing = (e) => {
  isDrawing.value = true;
  const { x, y } = getPos(e);
  ctx.value.beginPath();
  ctx.value.moveTo(x, y);
};

const draw = (e) => {
  if (!isDrawing.value) return;
  const { x, y } = getPos(e);
  ctx.value.lineTo(x, y);
  ctx.value.stroke();
};

const stopDrawing = () => {
  if (!isDrawing.value) return;
  isDrawing.value = false;
  save();
};

const clear = () => {
  const c = canvas.value;
  ctx.value.clearRect(0, 0, c.width, c.height);
  emit("update:image", null);
};

const save = () => {
  // Check if canvas is empty (optional but recommended)
  const dataURL = canvas.value.toDataURL("image/png");
  emit("update:image", dataURL);
};
</script>
<style scoped>
.fu-signature-wrapper {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* THE CANVAS */
.fu-signature-wrapper canvas {
  width: 100%;
  /* IMPORTANT: visual size */
  height: 140px;
  /* fixed drawing area */
  border: 1.5px solid #e2e8f0;
  border-radius: 8px;
  background: #fff;
  cursor: crosshair;
  touch-action: none;
  /* prevents scroll on mobile */
  display: block;
}

/* BUTTON AREA */
.fu-signature-controls {
  display: flex;
  justify-content: flex-end;
}

.fu-clear-btn {
  padding: 6px 10px;
  font-size: 11px;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  background: transparent;
  cursor: pointer;
  transition: 0.15s;
}

.fu-clear-btn:hover {
  background: #f3f4f6;
}
</style>
