<template>
  <div class="fu-empty" :class="[`fu-empty--${size}`, `fu-empty--${variant}`]">
    <!-- Visual -->
    <div v-if="visual && visual.type !== 'none'" class="fu-empty__visual">
      <component
        v-if="visual.type === 'icon'"
        :is="visual.value"
        class="fu-empty__icon"
      />
      <img
        v-else-if="visual.type === 'image'"
        :src="visual.src"
        :alt="visual.alt"
        class="fu-empty__image"
      />
    </div>

    <!-- Text -->
    <div class="fu-empty__body">
      <p class="fu-empty__title">{{ title }}</p>
      <p v-if="description" class="fu-empty__description">{{ description }}</p>
    </div>

    <!-- Actions -->
    <div v-if="primaryAction || secondaryActions?.length" class="fu-empty__actions">
      <FusionButton
        v-if="primaryAction"
        :text="primaryAction.label"
        buttonWidth="fit-content"
        @click="primaryAction.onClick?.()"
      />
      <FusionButton
        v-for="action in secondaryActions"
        :key="action.label"
        :text="action.label"
        buttonWidth="fit-content"
        variant="subtle"
        @click="action.onClick?.()"
      />
    </div>
  </div>
</template>

<script setup lang="ts">
import type { Component } from "vue";
import FusionButton from "@/components/button/FusionButton.vue";

interface Action {
  label: string;
  onClick?: () => void;
  href?: string;
}

interface EmptyStateProps {
  title: string;
  description?: string;
  visual?:
    | { type: "icon"; value: Component }
    | { type: "image"; src: string; alt: string }
    | { type: "none" };
  primaryAction?: Action;
  secondaryActions?: Action[];
  size?: "sm" | "md" | "lg";
  variant?: "default" | "subtle" | "minimal";
}

withDefaults(defineProps<EmptyStateProps>(), {
  size: "md",
  variant: "default",
});
</script>

