<template>
  <div v-if="isVisible" class="qu-widget" :data-widget-id="widgetId">
    <div class="qu-label-row">
      <div class="qu-label-render" v-html="safeLabel"></div>
      <span v-if="required" class="qu-required">*</span>
    </div>

    <div class="qu-input-area">
      <FusionTextInput
        v-if="questionType === 'short_text'"
        v-model="localValue"
        :placeholder="placeholder"
        variant="outline"
        formWrapperWidth="100%"
        size="md"
        @update:modelValue="emitValue"
      />

      <FusionTextArea
        v-else-if="questionType === 'long_text'"
        v-model="localValue"
        :placeholder="placeholder"
        variant="outline"
        formWrapperWidth="100%"
        @update:modelValue="emitValue"
      />

      <FusionTextInput
        v-else-if="questionType === 'number'"
        type="number"
        v-model="localValue"
        :placeholder="placeholder"
        variant="outline"
        formWrapperWidth="100%"
        size="md"
        @update:modelValue="emitValue"
      />

      <FusionTextInput
        v-else-if="questionType === 'link'"
        type="url"
        v-model="localValue"
        :placeholder="placeholder"
        variant="outline"
        formWrapperWidth="100%"
        size="md"
        @update:modelValue="emitValue"
      />

      <FusionDatePicker
        v-else-if="questionType === 'date'"
        v-model="localValue"
        variant="date"
        :placeholder="placeholder"
        size="md"
        formWrapperWidth="100%"
        @update:modelValue="emitValue"
      />

      <FusionStatusDropdown
        v-else-if="questionType === 'dropdown'"
        v-model="dropdownSelected"
        :options="dropdownOptions"
        :placeholder="placeholder"
        align="left"
        size="md"
        @update:modelValue="onDropdownChange"
      />

      <div v-else-if="questionType === 'single_choice'" class="qu-choices">
        <FusionRadio
          v-for="opt in options"
          :key="opt.id"
          v-model="localValue"
          :value="opt.id"
          :name="`qu-${widgetId}`"
          @update:modelValue="emitValue"
        >
          {{ opt.text }}
        </FusionRadio>
      </div>

      <div v-else-if="questionType === 'multiple_choice'" class="qu-choices">
        <FusionCheckbox
          v-for="opt in options"
          :key="opt.id"
          :modelValue="isChecked(opt.id)"
          :label="opt.text"
          @update:modelValue="toggleCheckbox(opt.id)"
        />
      </div>

      <FusionUpload
        v-else-if="questionType === 'upload'"
        accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx"
        :maxFiles="10"
        :maxFileSizeMB="15"
        multiple
        @update:modelValue="onUploadChange"
      />

      <!-- ── Contact details ── -->
      <div v-else-if="questionType === 'contact_details'" class="qu-contact">
        <div class="qu-contact-grid">
          <FusionTextInput
            v-model="contactValue.firstName"
            placeholder="First name"
            variant="outline"
            formWrapperWidth="100%"
            size="md"
            @update:modelValue="emitContact"
          />
          <FusionTextInput
            v-model="contactValue.lastName"
            placeholder="Last name"
            variant="outline"
            formWrapperWidth="100%"
            size="md"
            @update:modelValue="emitContact"
          />
        </div>
        <FusionTextInput
          v-if="contactFields?.email !== false"
          v-model="contactValue.email"
          type="email"
          placeholder="Email address"
          variant="outline"
          formWrapperWidth="100%"
          size="md"
          @update:modelValue="emitContact"
        />
        <FusionTextInput
          v-if="contactFields?.phone !== false"
          v-model="contactValue.phone"
          type="tel"
          placeholder="Phone number"
          variant="outline"
          formWrapperWidth="100%"
          size="md"
          @update:modelValue="emitContact"
        />
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch } from "vue";

import FusionTextInput from "@/components/TextInput/FusionTextInput.vue";
import FusionTextArea from "@/components/textArea/FusionTextArea.vue";
import FusionDatePicker from "@/components/datePicker/dateField/FusionDatePicker.vue";
import FusionStatusDropdown from "@/components/StatusDropdown/FusionStatusDropdown.vue";
import FusionRadio from "@/components/radio/FusionRadio.vue";
import FusionCheckbox from "@/components/checkbox/FusionCheckbox.vue";
import FusionUpload from "@/components/fileUploader/FusionUpload.vue";

type Option = { id: string | number; text: string };

type QuestionType =
  | "short_text"
  | "long_text"
  | "number"
  | "link"
  | "date"
  | "dropdown"
  | "single_choice"
  | "multiple_choice"
  | "upload"
  | "contact_details";

type ContactValue = {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
};

const props = withDefaults(
  defineProps<{
    widgetId: string | number;
    questionType?: QuestionType;
    label?: string;
    placeholder?: string;
    required?: boolean;
    options?: Option[];
    value?: any;
    isVisible?: boolean;
    contactFields?: { email?: boolean; phone?: boolean };
  }>(),
  {
    questionType: "short_text",
    label: "",
    placeholder: "",
    required: false,
    options: () => [],
    value: null,
    isVisible: true,
    contactFields: () => ({ email: true, phone: true }),
  }
);

const emit = defineEmits<{
  (e: "update", payload: { value: any }): void;
}>();

// ── Local value (all types except contact_details) ────────────────────────

const localValue = ref<any>(
  props.questionType === "multiple_choice"
    ? Array.isArray(props.value)
      ? [...props.value]
      : []
    : props.questionType === "contact_details"
    ? null
    : props.value ?? ""
);

// ── Contact value ─────────────────────────────────────────────────────────

const emptyContact = (): ContactValue => ({
  firstName: "",
  lastName: "",
  email: "",
  phone: "",
});

const contactValue = ref<ContactValue>(
  props.value && typeof props.value === "object"
    ? { ...emptyContact(), ...props.value }
    : emptyContact()
);

// ── Safe label ────────────────────────────────────────────────────────────

const safeLabel = computed(() => {
  if (!props.label) return "";
  return props.label.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, "");
});

// ── Dropdown helpers ──────────────────────────────────────────────────────

const dropdownOptions = computed(() =>
  props.options.map((o: Option) => ({ label: o.text, _id: o.id }))
);

const dropdownSelected = computed({
  get() {
    return dropdownOptions.value.find((o) => o._id === localValue.value) || null;
  },
  set(opt: any) {
    localValue.value = opt?._id ?? null;
  },
});

// ── Watchers ──────────────────────────────────────────────────────────────

watch(
  () => props.value,
  (newVal) => {
    if (props.questionType === "contact_details") {
      contactValue.value =
        newVal && typeof newVal === "object"
          ? { ...emptyContact(), ...newVal }
          : emptyContact();
    } else {
      localValue.value =
        props.questionType === "multiple_choice"
          ? Array.isArray(newVal)
            ? [...newVal]
            : []
          : newVal ?? "";
    }
  }
);

watch(
  () => props.isVisible,
  (visible) => {
    if (!visible) {
      if (props.questionType === "contact_details") {
        contactValue.value = emptyContact();
        emit("update", { value: emptyContact() });
      } else {
        const empty = props.questionType === "multiple_choice" ? [] : null;
        localValue.value = empty;
        emit("update", { value: empty });
      }
    }
  }
);

// ── Emit helpers ──────────────────────────────────────────────────────────

function emitValue() {
  emit("update", { value: localValue.value });
}

function emitContact() {
  emit("update", { value: { ...contactValue.value } });
}

function onDropdownChange(opt: any) {
  localValue.value = opt?._id ?? null;
  emitValue();
}

function onUploadChange(files: any) {
  localValue.value = files;
  emitValue();
}

function isChecked(optId: string | number): boolean {
  return Array.isArray(localValue.value) && localValue.value.includes(optId);
}

function toggleCheckbox(optId: string | number) {
  const arr = Array.isArray(localValue.value) ? [...localValue.value] : [];
  const idx = arr.indexOf(optId);
  if (idx === -1) arr.push(optId);
  else arr.splice(idx, 1);
  localValue.value = arr;
  emitValue();
}
</script>

<style scoped>
.qu-widget {
  padding: 12px 0;
  transition: opacity 0.2s ease-in-out;
}
.qu-label-row {
  display: flex;
  align-items: flex-start;
  gap: 4px;
  margin-bottom: 8px;
}
.qu-label-render {
  font-size: 14px;
  font-weight: 600;
  color: #111827;
  line-height: 1.5;
}
.qu-required {
  color: #ef4444;
  font-weight: 700;
}
.qu-input-area {
  width: 100%;
}
.qu-choices {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

/* ── Contact details ── */
.qu-contact {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.qu-contact-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}
</style>
