<script lang="ts" setup>
import { computed } from "vue";

const props = defineProps<{
  title?: string;
  basis?: string | number;
  loading?: boolean;
}>();

const panelBasis = computed(() => {
  if (!props.basis) return "300px";
  return typeof props.basis === "number" ? `${props.basis}px` : props.basis;
});
</script>

<template>
  <div class="fu-panel" :style="{ flexBasis: panelBasis }">
    <!-- HEADER -->
    <div v-if="title || $slots.actions" class="fu-panel__header px-2">
      <div v-if="loading" class="fu-panel__title-skeleton" />
      <h3 v-else-if="title" class="fu-panel__title">{{ title }}</h3>
      <div v-if="$slots.actions && !loading" class="fu-panel__actions">
        <slot name="actions" />
      </div>
    </div>

    <!-- BODY WRAPPER -->
    <div class="fu-panel__body-wrapper">
      <div class="fu-panel__body scrollbar__control customScrollBar px-2">
        <template v-if="loading">
          <div class="fu-panel__skeleton-body">
            <div class="skeleton-line" style="width: 60%; height: 14px" />
            <div class="skeleton-line" style="width: 85%; height: 14px" />
            <div class="skeleton-line" style="width: 45%; height: 14px" />
            <div class="skeleton-line" style="width: 70%; height: 14px" />
            <div class="skeleton-line" style="width: 55%; height: 14px" />
          </div>
        </template>
        <slot v-else />
