<script setup>
import { computed } from "vue";

// ── Props — mirrors the editor widget props exactly, all optional ─────────────
const props = defineProps({
  variant: { type: String, default: "classic" },
  showServiceImages: { type: Boolean, default: true },
  showQty: { type: Boolean, default: true },
  showUnit: { type: Boolean, default: true },
  showPrice: { type: Boolean, default: true },
  showTax: { type: Boolean, default: true },

  header: {
    type: Object,
    default: () => ({
      showLogo: true,
      logoUrl: "",
      showCompany: true,
      companyName: "",
      companyEmail: "",
      companyPhone: "",
      companyAddress: "",
      showTitle: true,
      invoiceTitle: "INVOICE",
      showInvoiceNumber: true,
      invoiceNumber: "INV-001",
      showDate: true,
      invoiceDate: "",
      showDueDate: true,
      dueDate: "",
      showPO: false,
      poNumber: "",
      showBillTo: true,
      clientName: "",
      clientEmail: "",
      clientPhone: "",
      clientAddress: "",
      bgColor: "",
      borderColor: "",
    }),
  },

  serviceBlocks: { type: Array, default: () => [] },

  footer: {
    type: Object,
    default: () => ({ currency: "GBP", discounts: [], taxes: [] }),
  },
});

// ── Helpers──────
const today = new Date().toLocaleDateString("en-GB", {
  day: "numeric",
  month: "short",
  year: "numeric",
});

const currencySymbol = computed(() => {
  const c = props.footer?.currency || "GBP";
  return c === "USD" ? "$" : c === "EUR" ? "€" : "£";
});

function fmt(n) {
  return `${currencySymbol.value}${(n || 0).toLocaleString("en-GB", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;
}

function rowTotal(row) {
  return (row.qty || 0) * (row.price || 0);
}

// ── Totals───────
const subtotal = computed(() =>
  (props.serviceBlocks || []).reduce((acc, b) => {
    acc += rowTotal(b);
    (b.subItems || []).forEach((s) => (acc += rowTotal(s)));
    return acc;
  }, 0)
);

const taxableAmount = computed(() =>
  (props.serviceBlocks || []).reduce((acc, b) => {
    if (b.taxable) acc += rowTotal(b);
    (b.subItems || []).forEach((s) => {
      if (s.taxable) acc += rowTotal(s);
    });
    return acc;
  }, 0)
);

const singleTax = computed(() => {
  const taxes = props.footer?.taxes;
  return Array.isArray(taxes) && taxes.length ? taxes[0] : { label: "Tax", rate: 0 };
});

const totalDiscount = computed(() =>
  (props.footer?.discounts || []).reduce(
    (acc, d) => acc + (subtotal.value * (d.percent || 0)) / 100,
    0
  )
);

const totalTax = computed(
  () => (taxableAmount.value * (singleTax.value.rate || 0)) / 100
);
const total = computed(() => subtotal.value - totalDiscount.value + totalTax.value);

// ── Style helpers
const headerBgStyle = computed(() => {
  const s = {};
  if (props.header?.bgColor) s.backgroundColor = props.header.bgColor;
  if (props.header?.borderColor) s.borderBottomColor = props.header.borderColor;
  return s;
});

const dividerStyle = computed(() =>
  props.header?.borderColor ? { background: props.header.borderColor } : {}
);

const modernBandStyle = computed(() =>
  props.header?.bgColor ? { background: props.header.bgColor } : { background: "#111827" }
);

const modernTotalStyle = computed(() =>
  props.variant === "modern" && props.header?.bgColor
    ? { background: props.header.bgColor }
    : {}
);

const itemsGridStyle = computed(() => {
  const cols = [
    "1fr",
    props.showQty ? "60px" : null,
    props.showUnit ? "68px" : null,
    props.showPrice ? "80px" : null,
    props.showTax ? "32px" : null,
    "88px",
  ]
    .filter(Boolean)
    .join(" ");
  return { "--fip-cols": cols };
});
</script>

