<template>
  <div class="fu-tabs">
    <!-- Tab Headers -->
    <div class="fu-tabs__header-wrapper">
      <div class="fu-tabs-buttons scrollbar__control customScrollBar">
        <button
          v-for="tab in visibleTabs"
          :key="tab.key"
          @click="setActive(tab.key)"
          class="fu-tab"
          :class="{ 'fu-tab--active': activeTab === tab.key }"
          :disabled="tab.disabled"
        >
          <!-- AVATAR -->
          <div v-if="tab.avatarSrc || tab.avatarText" class="fu-tab__avatar">
            <img
              v-if="tab.avatarSrc"
              :src="tab.avatarSrc"
              class="fu-tab__avatar-img"
              alt="avatar"
            />
            <div v-else class="fu-tab__avatar-fallback">
              {{ tab.avatarText?.charAt(0)?.toUpperCase() }}
            </div>
          </div>

          <!-- ICON -->
          <component
            v-else-if="tab.icon"
            :is="tab.icon"
            :size="16"
            class="fu-tab__icon"
          />

          <!-- TITLE -->
          <span
            v-if="!tab.avatarSrc && !tab.avatarText && tab.title"
            class="fu-tab__title"
          >
            {{ tab.title }}
          </span>

          <!-- COUNT -->
          <span v-if="typeof tab.count === 'number'" class="fu-tab__count">
            {{ tab.count }}
          </span>
        </button>
      </div>
    </div>

    <!-- Tab Body -->
    <div class="fu-tabs__content-wrapper">
      <div class="fu-tabs__body scrollbar__control customScrollBar" ref="tabBody">
        <keep-alive>
          <div
            v-for="tab in visibleTabs"
            :key="tab.key"
            class="fu-tab-panel"
            v-show="activeTab === tab.key"
          >
            <slot :name="tab.key" />
          </div>
        </keep-alive>
      </div>

      <div class="fu-tabs__footer" v-if="$slots.footer">
        <slot name="footer" />
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, onBeforeUnmount, nextTick } from "vue";

const props = defineProps({
  tabs: Array,
  defaultActiveDesktop: String,
  defaultActiveMobile: String,
});

const emit = defineEmits(["tab-change"]);

const isMobile = ref(window.innerWidth <= 768);
const activeTab = ref("");
const tabBody = ref(null);

const visibleTabs = computed(() =>
  props.tabs.filter((t) => !t.mobileOnly || isMobile.value)
);

function wakeScroll() {
  const el = tabBody.value;
  if (!el) return;
  el.style.overflowY = "hidden";
  requestAnimationFrame(() => {
    el.style.overflowY = "auto";
  });
}

function setActive(key) {
  const tab = props.tabs.find((t) => t.key === key);
  if (!tab || tab.disabled) return;

  activeTab.value = key;
  emit("tab-change", key);

  nextTick(() => {
    const el = tabBody.value;
    if (!el) return;
    el.scrollTop = 0;
    wakeScroll();
  });
}

function setDefaultTab() {
  const fallback = props.tabs[0]?.key;

  const key = isMobile.value
    ? props.defaultActiveMobile || fallback
    : props.defaultActiveDesktop || fallback;

  activeTab.value = key;
}

function updateDevice() {
  const wasMobile = isMobile.value;
  isMobile.value = window.innerWidth <= 768;
  if (wasMobile !== isMobile.value) nextTick(setDefaultTab);
}

onMounted(() => {
  updateDevice();
  setDefaultTab();
  wakeScroll();
  window.addEventListener("resize", updateDevice);
});

onBeforeUnmount(() => {
  window.removeEventListener("resize", updateDevice);
});
defineExpose({ setActive });
</script>

