<template>
  <div class="fu-embed" :style="embedStyle">
    <!-- ── No scheduler in document ── -->
    <div v-if="!schedulerWidget" class="fu-embed-error-state">
      <div class="fu-embed-error-state__icon">📅</div>
      <p class="fu-embed-error-state__title">No scheduler found</p>
      <p class="fu-embed-error-state__sub">
        This document doesn't contain a booking widget.
      </p>
    </div>

    <template v-else>
      <!-- ── Success ── -->
      <div v-if="stage === 'submitted'" class="fu-embed-success">
        <div class="fu-embed-success__icon">✓</div>
        <p class="fu-embed-success__title">You're booked in</p>
        <p class="fu-embed-success__sub">{{ formatSlotSummary }}</p>
      </div>

      <!-- ── Scheduler panel ── -->
      <div v-else-if="stage === 'idle'" class="fu-panel">
        <FuSchedulerWidget
          v-bind="schedulerWidget.props"
          :widgetId="schedulerWidget.id"
          @update="onSchedulerUpdate"
        />
      </div>

      <!-- ── Form panel ── -->
      <div v-else-if="stage === 'form'" class="fu-panel">
        <div class="fu-form-slot-bar">
          <button class="fu-form-slot-bar__back" @click="goBack">
            <span>←</span> Change time
          </button>
          <span class="fu-form-slot-bar__date">{{ formatSlotSummary }}</span>
        </div>

        <div class="fu-embed-questions">
          <template v-for="q in questionWidgets" :key="q.id">
            <FuQuestionRenderer
              v-bind="q.props"
              :widgetId="q.id"
              :isVisible="isQuestionVisible(q)"
              :class="{ 'fu-embed-question--error': errors.has(q.id) }"
              @update="(p: any) => onQuestionUpdate(q.id, p)"
            />
            <p v-if="errors.has(q.id)" class="fu-embed-error">This field is required</p>
          </template>
        </div>

        <button class="fu-embed-submit" :disabled="submitting" @click="submit">
          <span v-if="!submitting">Confirm booking</span>
          <span v-else class="fu-embed-submit__spinner" />
        </button>
      </div>
    </template>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, shallowRef } from "vue";
import FuSchedulerWidget from "@/components/editor/scheduler/FuSchedulerWidget.vue";
import FuQuestionRenderer from "@/components/editor/questionRender/FuQuestionRenderer.vue";

const props = defineProps<{ document: any }>();

const emit = defineEmits<{
  (e: "submit", payload: { slot: any; answers: Record<string, any> }): void;
}>();

// ── Flatten ───────────────────────────────────────────────────────────────

function flattenWidgets(doc: any): any[] {
  const out: any[] = [];
  for (const page of doc?.pages ?? [])
    for (const block of page?.blocks ?? [])
      for (const col of block?.columns ?? [])
        for (const widget of col?.widgets ?? []) out.push(widget);
  return out;
}

const allWidgets = computed(() => flattenWidgets(props.document));
const schedulerWidget = computed(() =>
  allWidgets.value.find((w) => w.type === "scheduler")
);
const questionWidgets = computed(() =>
  allWidgets.value.filter((w) => w.type === "question")
);

// ── Stage ─────────────────────────────────────────────────────────────────

const stage = ref<"idle" | "form" | "submitted">("idle");
const bookedSlot = shallowRef<any>(null);

function onSchedulerUpdate(payload: any) {
  bookedSlot.value = payload.bookedSlot;
  stage.value = questionWidgets.value.length ? "form" : "submitted";
}

function goBack() {
  stage.value = "idle";
  answers.value = {};
  errors.value = new Set();
}

// ── Answers ───────────────────────────────────────────────────────────────

const answers = ref<Record<string, any>>({});

function onQuestionUpdate(widgetId: string, payload: any) {
  answers.value = { ...answers.value, [widgetId]: payload.value };
  errors.value.delete(widgetId);
}

// ── Conditions ────────────────────────────────────────────────────────────

function isQuestionVisible(q: any): boolean {
  const conditions: any[] = q.props.conditions ?? [];
  if (!conditions.length) return true;
  const logic = q.props.conditionLogic ?? "all";
  const results = conditions.map((cond) => {
    const sourceVal = answers.value[cond.sourceWidgetId];
    switch (cond.operator) {
      case "equals":
        return sourceVal === cond.value;
      case "not_equals":
        return sourceVal !== cond.value;
      case "contains":
        return Array.isArray(sourceVal)
          ? sourceVal.includes(cond.value)
          : String(sourceVal ?? "").includes(cond.value);
      default:
        return true;
    }
  });
  return logic === "all" ? results.every(Boolean) : results.some(Boolean);
}

// ── Validation ────────────────────────────────────────────────────────────

const errors = ref<Set<string>>(new Set());

function validate(): boolean {
  const next = new Set<string>();
  for (const q of questionWidgets.value) {
    if (!isQuestionVisible(q) || !q.props.required) continue;
    const val = answers.value[q.id];
    const empty =
      val === null ||
      val === undefined ||
      val === "" ||
      (Array.isArray(val) && !val.length);
    if (empty) next.add(q.id);
  }
  errors.value = next;
  return next.size === 0;
}

// ── Submit ────────────────────────────────────────────────────────────────

const submitting = ref(false);

async function submit() {
  if (!bookedSlot.value || !validate()) return;
  submitting.value = true;
  try {
    emit("submit", { slot: bookedSlot.value, answers: answers.value });
    stage.value = "submitted";
  } finally {
    submitting.value = false;
  }
}

// ── Helpers ───────────────────────────────────────────────────────────────

const formatSlotSummary = computed(() => {
  if (!bookedSlot.value?.date) return "";
  return new Date(bookedSlot.value.date).toLocaleString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });
});

const embedStyle = computed(() => {
  const brand = props.document?.meta?.theme?.brandColor ?? "#4f46e5";
  return {
    "--embed-brand": brand,
    "--embed-brand-light": brand + "18",
    "--embed-brand-mid": brand + "44",
  };
});
</script>

