// @/registry/widgetRegistry.ts
import { defineAsyncComponent, type Component } from 'vue';

// Define the shape of our registry to satisfy TypeScript
interface Registry {
  components: Record<string, Component>;
  resolve: (type: string) => Component | null;
}

export const widgetRegistry: Registry = {
  components: {
    text: defineAsyncComponent(() => import('@/components/editor/textRender/TextRenderer.vue')),
    image: defineAsyncComponent(() => import('@/components/editor/imageRender/ImageRenderer.vue')),
    video: defineAsyncComponent(() => import('@/components/editor/videoRender/FuVideoRenderer.vue')),
    divider: defineAsyncComponent(() => import('@/components/editor/dividerRender/DividerRenderer.vue')),
    service: defineAsyncComponent(() => import('@/components/editor/serviceRender/ServiceRenderer.vue')),
    question: defineAsyncComponent(() => import('@/components/editor/questionRender/FuQuestionRenderer.vue')),
    scheduler: defineAsyncComponent(() => import('@/components/editor/scheduler/FuSchedulerWidget.vue')),
    invoice: defineAsyncComponent(() => import('@/components/editor/invoiceRender/FuinvoicePreview.vue')),
     contract: defineAsyncComponent(() => import('@/components/editor/contract/FuContractRenderer.vue')),
  },

  resolve(type: string) {
    const component = this.components[type];
    if (!component) {
      console.warn(`⚠️ Widget type "${type}" not registered.`);
      return null;
    }
    return component;
  }
};