<template>
  <div class="divider-widget" :style="dividerStyle"></div>
</template>

<script setup>
import { computed } from "vue";

// Define the props directly from the widget object
const props = defineProps({
  widget: {
    type: Object,
    required: true,
  },
});

// Extract necessary properties from the widget object
const {
  color,
  thickness,
  width,
  styleType,
  alignment,
  marginTop,
  marginBottom,
} = props.widget;

// Computed styles based on the widget props
const dividerStyle = computed(() => {
  let justify = "center";
  if (alignment === "left") justify = "flex-start";
  else if (alignment === "right") justify = "flex-end";

  return {
    display: "flex",
    justifyContent: justify,
    width: "100%",
    marginTop: marginTop + "px",
    marginBottom: marginBottom + "px",
    "--divider-color": color || "#CBD5E1",
    "--divider-thickness": thickness + "px" || "1px",
    "--divider-style": styleType || "solid",
  };
});
</script>

<style scoped>
.divider-widget::before {
  content: "";
  display: block;
  width: 100%;
  border-bottom: var(--divider-thickness) var(--divider-style) var(--divider-color);
  transition: all 0.2s ease;
}

.divider-widget:hover::before {
  opacity: 0.9;
}
</style>
