<template>
  <div class="fu-image-widget" :class="alignmentClass" :style="wrapperStyle">
    <!-- EMPTY STATE -->
    <div v-if="!src" class="fu-empty-state">
      <ImageIcon :size="32" />
      <span>Image</span>
    </div>

    <!-- IMAGE -->
    <div v-else class="fu-image-container" :style="containerStyle">
      <img :src="src" :alt="alt" class="fu-image" :style="imageStyle" draggable="false" />
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";
import { ImageIcon } from "lucide-vue-next";

/* ─────────────────────────────
   TYPES
───────────────────────────── */

type Alignment = "left" | "center" | "right" | "stretch";

interface ImageWidgetProps {
  src?: string;
  alt?: string;
  alignment?: Alignment;
  imageWidth?: number;
  opacity?: number;
  borderRadius?: number;
}

interface ImageWidget {
  props?: ImageWidgetProps;
}

/* ─────────────────────────────
   PROPS
───────────────────────────── */

const props = defineProps<{
  widget: ImageWidget;
}>();

/* ─────────────────────────────
   NORMALIZED PROPS
───────────────────────────── */

const config = computed(() => props.widget?.props ?? {});

const src = computed(() => config.value.src ?? "");
const alt = computed(() => config.value.alt ?? "Image");

const alignment = computed<Alignment>(() => config.value.alignment ?? "center");
const width = computed(() => config.value.imageWidth);
const opacity = computed(() => config.value.opacity ?? 100);
const radius = computed(() => config.value.borderRadius ?? 8);

/* ─────────────────────────────
   LAYOUT
───────────────────────────── */

const alignmentClass = computed(() => `is-${alignment.value}`);

const wrapperStyle = computed(() => ({
  width: "100%",
  display: "flex",
  justifyContent:
    alignment.value === "left"
      ? "flex-start"
      : alignment.value === "right"
      ? "flex-end"
      : "center",
}));

const containerStyle = computed(() => {
  const isStretch = alignment.value === "stretch";

  return {
    width: isStretch ? "100%" : width.value ? `${width.value}px` : "auto",
    maxWidth: "100%",
  };
});

const imageStyle = computed(() => ({
  width: "100%",
  height: "auto",
  display: "block",
  opacity: opacity.value / 100,
  borderRadius: `${radius.value}px`,
}));
</script>

<style scoped>
.fu-image-widget {
  width: 100%;
}

/* EMPTY */
.fu-empty-state {
  height: 160px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
  justify-content: center;
  background: #f5f7ff;
  color: #64748b;
  font-size: 13px;
  border-radius: 8px;
}

/* IMAGE */
.fu-image {
  user-select: none;
}

/* ALIGNMENT */
.is-left {
  justify-content: flex-start;
}
.is-center {
  justify-content: center;
}
.is-right {
  justify-content: flex-end;
}
.is-stretch {
  justify-content: center;
}
</style>
