<template>
  <div
    class="fu-combobox"
    :class="{ 'fu-combobox--disabled': disabled }"
    ref="comboboxRef"
  >
    <!-- Control -->
    <div class="fu-combobox__control">
      <input
        type="text"
        :value="isOpen ? searchQuery : selectedOption?.label || ''"
        :placeholder="placeholder"
        class="fu-combobox__input"
        :disabled="disabled"
        @input="onInput"
        @focus="!disabled && (isOpen = true)"
      />
      <span class="fu-combobox__icon" @click.stop="toggleOpen">
        <ChevronDown :size="18" :stroke-width="1" />
      </span>
    </div>

    <!-- Dropdown -->
    <div
      v-if="isOpen && !disabled"
      class="fu-combobox__dropdown scrollbar__control customScrollBar"
    >
      <template v-if="groupedOptions.length > 0">
        <div
          v-for="group in groupedOptions"
          :key="group.title"
          class="fu-combobox__group"
        >
          <div class="fu-combobox__group-title">{{ group.title }}</div>

          <div
            v-for="option in group.items"
            :key="option.value"
            class="fu-combobox__option"
            :class="{
              'fu-combobox__option--selected': option.value === selectedOption?.value,
            }"
            @click="selectOption(option)"
          >
            <!-- Left -->
            <div class="fu-combobox__option-left">
              <slot name="option" :option="option">
                <component
                  v-if="option.icon"
                  :is="option.icon"
                  class="fu-combobox__option-icon"
                />
                <span>{{ option.label }}</span>
              </slot>
            </div>

            <!-- Right -->
            <div class="fu-combobox__option-right">
              <Check
                v-if="option.value === selectedOption?.value"
                class="fu-combobox__check"
              />
            </div>
          </div>
        </div>
      </template>
      <div v-else class="fu-combobox__empty">No results found</div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, onMounted, onBeforeUnmount } from "vue";
import { ChevronDown, Check } from "lucide-vue-next";

export interface ComboboxOption {
  label: string;
  value: string | number;
  icon?: any;
  group?: string;
}

const props = defineProps<{
  options: ComboboxOption[];
  modelValue?: string | number | null;
  placeholder?: string;
  disabled?: boolean;
}>();

const emit = defineEmits<{
  (e: "update:modelValue", value: string | number | null): void;
}>();

const isOpen = ref(false);
const searchQuery = ref("");
const selectedOption = ref<ComboboxOption | null>(null);
const comboboxRef = ref<HTMLElement | null>(null);

// Group + filter options
const groupedOptions = computed(() => {
  // If there is no search → show all options
  if (!searchQuery.value) {
    return buildGroups(props.options);
  }

  // If the search text === selected option label → show all options but keep highlight
  if (
    selectedOption.value &&
    searchQuery.value.toLowerCase() === selectedOption.value.label.toLowerCase()
  ) {
    return buildGroups(props.options);
  }

  // Otherwise → filter
  const filtered = props.options.filter((opt) =>
    opt.label.toLowerCase().includes(searchQuery.value.toLowerCase())
  );
  return buildGroups(filtered);
});

// Helper for grouping
function buildGroups(list: ComboboxOption[]) {
  const groups: Record<string, ComboboxOption[]> = {};
  list.forEach((opt) => {
    const group = opt.group || "Options";
    if (!groups[group]) groups[group] = [];
    groups[group].push(opt);
  });
  return Object.entries(groups).map(([title, items]) => ({ title, items }));
}

// Sync selected option with modelValue
watch(
  () => props.modelValue,
  (val) => {
    selectedOption.value = props.options.find((opt) => opt.value === val) || null;

    // Always sync searchQuery with selected label when closed
    if (!isOpen.value && selectedOption.value) {
      searchQuery.value = selectedOption.value.label;
    }
  },
  { immediate: true }
);

function onInput(e: Event) {
  searchQuery.value = (e.target as HTMLInputElement).value;
}

function selectOption(option: ComboboxOption) {
  selectedOption.value = option;
  searchQuery.value = option.label;
  emit("update:modelValue", option.value);
  isOpen.value = false;
}

function toggleOpen() {
  isOpen.value = !isOpen.value;
}

function handleClickOutside(e: MouseEvent) {
  if (comboboxRef.value && !comboboxRef.value.contains(e.target as Node)) {
    isOpen.value = false;

    if (selectedOption.value) {
      searchQuery.value = selectedOption.value.label;
    }
  }
}

onMounted(() => {
  document.addEventListener("click", handleClickOutside);
});

onBeforeUnmount(() => {
  document.removeEventListener("click", handleClickOutside);
});
</script>

<style lang="scss" scoped>
@use "FuCombobox.scss";
