<template>
  <div
    class="fu-dropdown-inline"
    ref="inlineRef"
    :class="{
      'fu-dropdown-inline--disabled': disabled,
      'fu-dropdown-inline--readonly': readonly,
    }"
  >
    <!-- Input-like display with color dot -->
    <div class="fu-dropdown-inline__wrapper">
      <span
        v-if="selected"
        class="fu-dropdown-inline__dot"
        :style="{ backgroundColor: selected.color }"
      ></span>
      <input
        ref="inputRef"
        type="text"
        class="fu-dropdown-inline__input"
        :value="selected?.label || ''"
        :placeholder="placeholder"
        readonly
        :disabled="disabled"
        @focus="openDropdown"
      />
    </div>
    <!-- Dropdown list -->
    <teleport to="body">
      <ul v-if="editing" class="fu-dropdown-inline__menu" :style="dropdownStyle">
        <li
          v-for="option in options"
          :key="option.label"
          class="fu-dropdown-inline__item"
          @mousedown.prevent="selectOption(option)"
        >
          <span
            class="fu-dropdown-inline__dot"
            :style="{ backgroundColor: option.color }"
          ></span>
          {{ option.label }}
        </li>
      </ul>
    </teleport>
  </div>
</template>

<script setup lang="ts">
import { ref, watch, onMounted, onBeforeUnmount } from "vue";

interface Option {
  label: string;
  color: string;
}

const props = defineProps<{
  modelValue: Option | null;
  options: Option[];
  placeholder?: string;
  isOpen?: boolean;
  disabled?: boolean;
  readonly?: boolean;
}>();

const emit = defineEmits<{
  (e: "update:modelValue", value: Option): void;
  (e: "open"): void;
  (e: "close"): void;
}>();

const inlineRef = ref<HTMLElement | null>(null);
const inputRef = ref<HTMLInputElement | null>(null);
const selected = ref<Option | null>(props.modelValue || null);
const editing = ref(false);
const dropdownStyle = ref<Record<string, string>>({});

watch(
  () => props.modelValue,
  (val) => (selected.value = val)
);

watch(
  () => props.isOpen,
  (val) => {
    if (props.disabled || props.readonly) return;
    editing.value = !!val;
    if (val) updatePosition();
  }
);

function openDropdown() {
  if (props.disabled || props.readonly) return;
  if (!editing.value) {
    emit("open");
  }
  editing.value = true;
  updatePosition();
}

function selectOption(option: Option) {
  selected.value = option;
  emit("update:modelValue", option);
  emit("close");
  editing.value = false;
  inputRef.value?.blur();
}

function handleClickOutside(e: MouseEvent) {
  if (inlineRef.value && !inlineRef.value.contains(e.target as Node)) {
    if (editing.value) emit("close");
    editing.value = false;
  }
}

function updatePosition() {
  const el = inlineRef.value;
  if (!el) return;
  const rect = el.getBoundingClientRect();
  dropdownStyle.value = {
    position: "absolute",
    top: `${rect.bottom + 4}px`,
    left: `${rect.left}px`,
    width: `${rect.width}px`,
    zIndex: "9999",
  };
}

onMounted(() => {
  window.addEventListener("click", handleClickOutside);
  window.addEventListener("resize", updatePosition);
});

onBeforeUnmount(() => {
  window.removeEventListener("click", handleClickOutside);
  window.removeEventListener("resize", updatePosition);
});
</script>

